para.programlisting:
dt = datetime() + hours(0:4)';
double = [12.5; 8; 0.75; 53.26; 8.42];
bool = [%t; %f; %t; %f; %t];
str = "A" + string(0:4)';
ts = timeseries(dt, double, bool, str, "VariableNames", ["datetime", "double", "bool", "string"])

//           datetime           double   bool   string
//    _______________________   ______   ____   ______
//                                                        
//    2026-03-27 12:02:13.297   12.5     T      A0    
//    2026-03-27 13:02:13.297   8        F      A1    
//    2026-03-27 14:02:13.297   0.75     T      A2    
//    2026-03-27 15:02:13.297   53.26    F      A3    
//    2026-03-27 16:02:13.297   8.42     T      A4    

path = fullfile(TMPDIR, "timeseries.xlsx");
xlsxSheet(path, "create", "timeseriesSheet"); // create timeseriesSheet
writetimeseries(ts, path, "sheet", "timeseriesSheet"); // write timeseries in timeseriesSheet
ts2 = readtimeseries(path, "sheet", "timeseriesSheet")

// ts2 = [5x3 timeseries]

//          datetime           double   bool   string
//   _______________________   ______   ____   ______
